concept.syntax:
// if as expression
val max = if (a > b) a else b

// when with a value
when (x) {
    1    -> println("one")
    2, 3 -> println("two or three")
    in 4..9 -> println("four to nine")
    else -> println("other")
}

// when without argument — cleaner if-else chain
val grade = when {
    score >= 90 -> "A"
    score >= 80 -> "B"
    else        -> "F"
}

demo.code:
fun grade(score: Int): String = when {
    score >= 90 -> "A"
    score >= 80 -> "B"
    score >= 70 -> "C"
    else        -> "F"
}

fun main() {
    println(grade(85))
    println(grade(62))
}

