practice.solutionCode:
fun describe(n: Int): String = when {
    n < 0       -> "negative"
    n == 0      -> "zero"
    n in 1..9   -> "small"
    else        -> "large"
}

fun main() {
    println(describe(-5))
    println(describe(0))
    println(describe(7))
    println(describe(42))
}
